import{_ as r,o as e,c as a,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-30.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-30.md"}'),o={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-05-30.md"};function n(l,t,s,h,d,c){return e(),a("div",null,[...t[0]||(t[0]=[i('<p>💡 光通訊追蹤日報 — 2026年5月30日（週六）</p><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-05-30 05:00 = 2026-05-29 21:00 UTC) <strong>昨日敘事延續</strong>：NVIDIA $150億矽光子投資 + Wiwynn COMPUTEX CPO 展示 + 台股光通訊族群續強 + CPO 商轉元年倒數</p></blockquote><hr><h2 id="🔴-即時指標-每日掃描" tabindex="-1">🔴 即時指標（每日掃描） <a class="header-anchor" href="#🔴-即時指標-每日掃描" aria-label="Permalink to &quot;🔴 即時指標（每日掃描）&quot;">​</a></h2><h3 id="指標1️⃣-輝達-nvidia-—-cpo-矽光子進展" tabindex="-1">指標1️⃣ 輝達 NVIDIA — CPO/矽光子進展 <a class="header-anchor" href="#指標1️⃣-輝達-nvidia-—-cpo-矽光子進展" aria-label="Permalink to &quot;指標1️⃣ 輝達 NVIDIA — CPO/矽光子進展&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li><strong>NVIDIA Spectrum-X Ethernet Photonics</strong>：世界首個可擴展 AI 工廠網路，整合 CPO 於 ASIC，頻寬達 409.6 Tb/s，<strong>2026 下半年上市</strong>（NVIDIA 官網）</li><li><strong>技術合作夥伴</strong>：Browave、Coherent、Corning、Fabrinet、FoxConn、Lumentum、Senko、SPIL、Sumitomo Electric、TSMC</li><li><strong>ISSCC 2026 論文</strong>：NVIDIA 發表「32Gb/s/λ 256Gb/s/Fiber Half-Rate DWDM Optical Link in 3D-Stacked 7nm EIC/65nm PIC」→ 技術藍圖揭示</li><li><strong>黃仁勳</strong>：台灣是 AI 革命中心，每年投資朝 1,500 億美元邁進</li><li><strong>Bernstein 97 頁報告</strong>（5/27）：CPO 故事「2026 年不會實現」，僅小批量出貨，真正爆發 2027+</li></ul><p><strong>評估</strong>：NVIDIA CPO 技術路線圖清晰（Spectrum-X H2 2026），但量產時程仍有分歧。COMPUTEX 將是重要觀察點。</p><p>📎 來源：<a href="https://www.nvidia.com/en-us/networking/products/silicon-photonics" target="_blank" rel="noreferrer">NVIDIA</a> · <a href="https://tspasemiconductor.substack.com/p/2026-nvidia-silicon-photonics-3d" target="_blank" rel="noreferrer">SemiVision</a> · <a href="https://www.panewslab.com/en/articles/019e3e04-f0be-7109-a843-b53a54f6ecf7" target="_blank" rel="noreferrer">Panewslab</a> （T: 05:00 TST）</p><hr><h3 id="指標2️⃣-博通-broadcom-—-cpo-dsp-產品動態" tabindex="-1">指標2️⃣ 博通 Broadcom — CPO/DSP 產品動態 <a class="header-anchor" href="#指標2️⃣-博通-broadcom-—-cpo-dsp-產品動態" aria-label="Permalink to &quot;指標2️⃣ 博通 Broadcom — CPO/DSP 產品動態&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>博通在交換器 ASIC 路線圖中明確列出 CPO 版本</li><li>與 NVIDIA 在 CPO 標準上既有競爭也有合作</li><li>2026 年被視為 CPO「商轉元年」，博通是關鍵玩家之一</li></ul><p><strong>評估</strong>：博通的 CPO 策略持續推進，但具體客戶採用進度未有新披露。</p><p>📎 來源：<a href="https://www.digitimes.com/news/a20260527PD211/ezconn-cpo-siph-2026.html" target="_blank" rel="noreferrer">DigiTimes</a> （T: 05:00 TST）</p><hr><h3 id="指標3️⃣-台積電-tsmc-—-coupe-cowos-先進封裝" tabindex="-1">指標3️⃣ 台積電 TSMC — COUPE/CoWoS 先進封裝 <a class="header-anchor" href="#指標3️⃣-台積電-tsmc-—-coupe-cowos-先進封裝" aria-label="Permalink to &quot;指標3️⃣ 台積電 TSMC — COUPE/CoWoS 先進封裝&quot;">​</a></h3><p><strong>最新動態</strong>：</p><ul><li>台積電 COUPE 技術已進入小批量產階段</li><li>CoWoS 產能持續擴張以滿足 AI 晶片需求</li><li>台積電（2330）5/28 盤中最高 2,360 元新天價，收 2,295 元；盤後鉅額交易出現 2,442 元新高價</li><li><strong>魏哲家</strong>：員工分紅增幅至少不低於去年（30%），鼓勵員工買進台積電股票</li><li>NVIDIA Spectrum-X 的技術合作夥伴包含 TSMC</li></ul><p><strong>評估</strong>：台積電先進封裝技術是 CPO 量產的關鍵基礎設施，COUPE 進展穩定。</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6471653" target="_blank" rel="noreferrer">鉅亨網</a> · <a href="https://money.udn.com/money/story/5607/9532290" target="_blank" rel="noreferrer">工商時報</a> （T: 05:00 TST）</p><hr><h3 id="指標4️⃣-csp-資本支出-—-無新公告" tabindex="-1">指標4️⃣ CSP 資本支出 — 無新公告 <a class="header-anchor" href="#指標4️⃣-csp-資本支出-—-無新公告" aria-label="Permalink to &quot;指標4️⃣ CSP 資本支出 — 無新公告&quot;">​</a></h3><p>本日無 Microsoft/Google/Amazon/Meta 新的資本支出公告。市場持續關注 AI 基礎設施投資強度。</p><p><strong>評估</strong>：CSP 資本支出維持高位，光通訊需求基本面不變。</p><p>📎 來源：無新公告（T: 05:00 TST）</p><hr><h2 id="🟡-台灣供應鏈個股動態" tabindex="-1">🟡 台灣供應鏈個股動態 <a class="header-anchor" href="#🟡-台灣供應鏈個股動態" aria-label="Permalink to &quot;🟡 台灣供應鏈個股動態&quot;">​</a></h2><h3 id="wiwynn-緯穎-—-🔴-重大-computex-2026-cpo-展示" tabindex="-1">Wiwynn（緯穎）— 🔴 重大：COMPUTEX 2026 CPO 展示 <a class="header-anchor" href="#wiwynn-緯穎-—-🔴-重大-computex-2026-cpo-展示" aria-label="Permalink to &quot;Wiwynn（緯穎）— 🔴 重大：COMPUTEX 2026 CPO 展示&quot;">​</a></h3><p><strong>5/28 宣佈</strong>：將在 COMPUTEX 2026（6/2-5）展示最新 CPO 互連技術</p><ul><li><strong>生態系合作夥伴</strong>：Ayar Labs、Global Unichip (GUC)、Browave、Corning、FOCI、Molex、SENKO、TE Connectivity</li><li><strong>展示重點</strong>： <ul><li>從晶片級 CPO 創新到資料中心級部署的全棧路徑</li><li>自研液冷解決方案（ELSFP 穩定光源）</li><li>高密度機箱內光纖路由</li><li>與 GUC 合作：系統級整合（從矽設計階段）</li><li>與 Ayar Labs 合作：機櫃級 AI 基礎設施</li></ul></li><li><strong>CEO William Lin</strong>：「AI 基礎設施正朝光電融合方向發展」</li></ul><p><strong>評估</strong>：Wiwynn 是 CPO 生態系的關鍵系統整合商，COMPUTEX 展示將是重要催化劑。</p><p>📎 來源：<a href="https://www.wiwynn.com/news/en/news/wiwynn-and-ecosystem-partners-to-showcase-co-packaged-optics-innovations-at-computex-2026" target="_blank" rel="noreferrer">Wiwynn</a> （T: 05:00 TST）</p><h3 id="聯亞-3081" tabindex="-1">聯亞 (3081) <a class="header-anchor" href="#聯亞-3081" aria-label="Permalink to &quot;聯亞 (3081)&quot;">​</a></h3><ul><li>本日無法說會或重大公告</li><li>MOCVD 機台擴產計畫延續前次</li><li><strong>評估</strong>：延續前次，本日無個股更新</li></ul><h3 id="光聖-6442" tabindex="-1">光聖 (6442) <a class="header-anchor" href="#光聖-6442" aria-label="Permalink to &quot;光聖 (6442)&quot;">​</a></h3><ul><li>子公司合聖 (He-sheng) FAU 產品已送樣美系大廠認證</li><li>預計 2026 下半年啟動小量試產，2027-2028 逐步放量</li><li>積極從傳統被動元件轉型至矽光子和 CPO 高階技術</li><li><strong>評估</strong>：FAU 送樣進度是近期重要觀察點</li></ul><p>📎 來源：<a href="https://technews.tw/2026/05/26/ezconn-fau-samples-us-manufacturer-certification-h2-trial-production/" target="_blank" rel="noreferrer">TechNews</a> （T: 05:00 TST）</p><h3 id="上詮-3363" tabindex="-1">上詮 (3363) <a class="header-anchor" href="#上詮-3363" aria-label="Permalink to &quot;上詮 (3363)&quot;">​</a></h3><ul><li>本日無法說會或重大公告</li><li><strong>評估</strong>：延續前次，本日無個股更新</li></ul><h3 id="智邦-2345" tabindex="-1">智邦 (2345) <a class="header-anchor" href="#智邦-2345" aria-label="Permalink to &quot;智邦 (2345)&quot;">​</a></h3><ul><li>本日無法說會或重大公告</li><li><strong>評估</strong>：延續前次，本日無個股更新</li></ul><h3 id="正文科技-zinwell" tabindex="-1">正文科技 (Zinwell) <a class="header-anchor" href="#正文科技-zinwell" aria-label="Permalink to &quot;正文科技 (Zinwell)&quot;">​</a></h3><ul><li>與以色列新創 New Photonics 合作推出 <strong>1.6Tbps 光收發模組</strong></li><li>目標應用於 GPU 和 AI 伺服器，符合 NVIDIA 光通訊傳輸標準</li><li>預計 2026 下半年完成驗證，2027 進入量產</li><li><strong>評估</strong>：1.6T 產品進度是重要里程碑</li></ul><p>📎 來源：<a href="https://today.line.me/tw/v3/article/wJKrON0" target="_blank" rel="noreferrer">Today Line</a> · <a href="https://www.businesstoday.com.tw/article/category/183008/post/202605270001/" target="_blank" rel="noreferrer">BUSINESS TODAY</a> （T: 05:00 TST）</p><h3 id="穩懋半導體-win-semi" tabindex="-1">穩懋半導體 (Win Semi) <a class="header-anchor" href="#穩懋半導體-win-semi" aria-label="Permalink to &quot;穩懋半導體 (Win Semi)&quot;">​</a></h3><ul><li>積極布局光通訊與矽光子市場</li><li>接收端 PD 產品預計 2026 Q2-Q3 進入量產 → 2026 光通訊業務主要成長動能</li><li>預估至 2030 年，光收發模組市場維持 ~33% CAGR</li><li><strong>評估</strong>：PD 量產進度值得追蹤</li></ul><p>📎 來源：<a href="https://money.udn.com/money/story/5612/9517639" target="_blank" rel="noreferrer">Money UDN</a> （T: 05:00 TST）</p><h3 id="達發科技-airoha" tabindex="-1">達發科技 (Airoha) <a class="header-anchor" href="#達發科技-airoha" aria-label="Permalink to &quot;達發科技 (Airoha)&quot;">​</a></h3><ul><li>預期 2026 年光通訊業務營收為去年的 <strong>3 倍以上</strong></li><li>50G SerDes PAM4 DSP + TIA 方案已切入多家全球前十大模組廠</li><li>單通道 100G SerDes PAM4 DSP 與全球前五大模組廠合作，預計年中量產</li><li><strong>評估</strong>：3 倍營收成長目標非常強勁</li></ul><p>📎 來源：<a href="https://www.ftnn.com.tw/news/548731" target="_blank" rel="noreferrer">FTNN</a> （T: 05:00 TST）</p><h3 id="頎邦科技-chipbond" tabindex="-1">頎邦科技 (Chipbond) <a class="header-anchor" href="#頎邦科技-chipbond" aria-label="Permalink to &quot;頎邦科技 (Chipbond)&quot;">​</a></h3><ul><li>光通訊專案訂單能見度已達 <strong>2028 年</strong></li><li>10 個相關專案進行中，掌握應對高頻訊號干擾的金凸塊技術</li><li><strong>評估</strong>：訂單能見度是重要利好</li></ul><p>📎 來源：<a href="https://money.udn.com/money/story/5612/9517639" target="_blank" rel="noreferrer">Money UDN</a> （T: 05:00 TST）</p><h3 id="友達-auo" tabindex="-1">友達 (AUO) <a class="header-anchor" href="#友達-auo" aria-label="Permalink to &quot;友達 (AUO)&quot;">​</a></h3><ul><li>積極布局 CPO 光通訊模組，與富采投控、鼎元建立生態系</li><li>Micro LED 技術應用於 CPO 模組基板、發射/接收元件</li><li>產品已進入送樣驗證階段，預計 2-3 年內發酵</li><li><strong>評估</strong>：友達從面板跨入 CPO 是長期布局</li></ul><p>📎 來源：<a href="https://money.udn.com/money/story/11162/9532285" target="_blank" rel="noreferrer">Money UDN</a> （T: 05:00 TST）</p><hr><h2 id="📊-產業趨勢摘要" tabindex="-1">📊 產業趨勢摘要 <a class="header-anchor" href="#📊-產業趨勢摘要" aria-label="Permalink to &quot;📊 產業趨勢摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 持續</td><td>800G/1.6T 光收發需求強勁</td></tr><tr><td>2026 商轉元年</td><td>🟡 關鍵時刻</td><td>Bernstein 報告提醒 CPO 僅小批量出貨</td></tr><tr><td>CPO 量產時程</td><td>🟡 延後風險</td><td>2026 小批量 → 2027 真正爆發</td></tr><tr><td>NVIDIA 光子投資</td><td>🟢 加碼</td><td>Spectrum-X H2 2026，409.6 Tb/s</td></tr><tr><td>台灣供應鏈擴產</td><td>🟢 穩步推進</td><td>Wiwynn COMPUTEX 展示、光聖 FAU、達發 DSP</td></tr><tr><td>Wiwynn CPO 生態系</td><td>🔴 重大</td><td>全棧展示，合作夥伴含 Ayar Labs/GUC/Corning</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>NVIDIA (2026): Spectrum-X Ethernet Photonics, 409.6 Tb/s, H2 2026</li><li>SemiVision (2026): NVIDIA ISSCC 2026 矽光子論文</li><li>Wiwynn (2026-05-28): COMPUTEX 2026 CPO 展示</li><li>TechNews (2026-05-26): 光聖 FAU 送樣美系大廠</li><li>BUSINESS TODAY (2026-05-27): 正文科技 1.6T 光收發模組</li><li>FTNN (2026-05): 達發光通訊營收 3 倍成長</li><li>Money UDN (2026-05-27): 頎邦訂單能見度至 2028</li><li>Money UDN (2026-05-27): 友達 CPO 模組布局</li><li>鉅亨網 (2026-05-28): 台積電盤後鉅額交易 $2,442</li><li>Panewslab (2026-05-27): Bernstein 97 頁報告，CPO 2026 不會實現</li><li>DigiTimes (2026-05-27): Ezconn CPO/矽光子進展</li></ol>',63)])])}const g=r(o,[["render",n]]);export{u as __pageData,g as default};
